const body = $input.first().json.body;

const VALID_MATERIALS = ['gold', 'silver', 'platinum'];
const VALID_TYPES = ['ring', 'necklace', 'bracelet', 'earring', 'pendant'];

if (!body.images || !Array.isArray(body.images) || body.images.length === 0) {
  throw new Error('No images provided');
}
if (body.images.length > 3) {
  throw new Error('Too many images (max 3)');
}
if (!body.description || body.description.trim().length === 0) {
  throw new Error('Description is required');
}
if (!VALID_MATERIALS.includes(body.material)) {
  throw new Error('Invalid material: ' + body.material);
}
if (!VALID_TYPES.includes(body.pieceType)) {
  throw new Error('Invalid piece type: ' + body.pieceType);
}

const mimeTypes = body.imageMimeTypes || body.images.map(() => 'image/jpeg');
const imageDataUrls = body.images.map(
  (b64, i) => `data:${mimeTypes[i] || 'image/jpeg'};base64,${b64}`
);

return [{
  json: {
    description: body.description.trim(),
    material: body.material,
    pieceType: body.pieceType,
    primaryImageDataUrl: imageDataUrls[0],
    allImageDataUrls: imageDataUrls,
  }
}];

