const PIECE_BASE_PRICE = {
  ring: 800,
  necklace: 1200,
  bracelet: 1000,
  earring: 600,
  pendant: 700,
};

const MATERIAL_MULTIPLIER = {
  silver: 1.0,
  gold: 1.5,
  platinum: 2.0,
};

const validatedInput = $('Validate Input').first().json;
const material = validatedInput.material;
const pieceType = validatedInput.pieceType;

const base = PIECE_BASE_PRICE[pieceType];
const multiplier = MATERIAL_MULTIPLIER[material];
const midpoint = base * multiplier;
const VARIANCE = 0.20;

const roundToFifty = (n) => Math.round(n / 50) * 50;
const priceMin = roundToFifty(midpoint * (1 - VARIANCE));
const priceMax = roundToFifty(midpoint * (1 + VARIANCE));

// After mergeByPosition the items arrive in order: front, side, perspective
const allItems = $input.all();
const frontB64       = allItems[0].json.data[0].b64_json;
const sideB64        = allItems[1].json.data[0].b64_json;
const perspectiveB64 = allItems[2].json.data[0].b64_json;

const materialLabel = { silver: 'Sterling Silver', gold: 'Gold', platinum: 'Platinum' };
const typeLabel = { ring: 'Ring', necklace: 'Necklace', bracelet: 'Bracelet', earring: 'Earring', pendant: 'Pendant' };

return [{
  json: {
    images: {
      front: frontB64,
      side: sideB64,
      perspective: perspectiveB64,
    },
    price: {
      min: priceMin,
      max: priceMax,
      currency: 'USD',
    },
    description: `Custom ${materialLabel[material]} ${typeLabel[pieceType]} — estimated fabrication cost based on material and design complexity.`,
  }
}];
